1900	  async function loginWithPasskey() {
1901	    if (!hasWebAuthn) return;
1902	    els.loginError.hidden = true;
1903	    try {
1904	      const begin = await (await fetch("/api/webauthn/auth/begin", { method: "POST" })).json();
1905	      if (begin.detail) throw new Error(begin.detail);
1906	      const o = begin.options;
1907	      o.challenge = _b64uToBuf(o.challenge);
1908	      if (o.allowCredentials) o.allowCredentials = o.allowCredentials.map((c) => ({ ...c, id: _b64uToBuf(c.id) }));
1909	      const asr = await navigator.credentials.get({ publicKey: o });
1910	      const payload = {
1911	        id: asr.id,
1912	        rawId: _bufToB64u(asr.rawId),
1913	        type: asr.type,
1914	        response: {
1915	          clientDataJSON: _bufToB64u(asr.response.clientDataJSON),
1916	          authenticatorData: _bufToB64u(asr.response.authenticatorData),
1917	          signature: _bufToB64u(asr.response.signature),
1918	          userHandle: asr.response.userHandle ? _bufToB64u(asr.response.userHandle) : null,
1919	        },
1920	        clientExtensionResults: asr.getClientExtensionResults ? asr.getClientExtensionResults() : {},
1921	      };
1922	      const res = await fetch("/api/webauthn/auth/complete", {
1923	        method: "POST",
1924	        headers: { "Content-Type": "application/json" },
1925	        body: JSON.stringify({ challenge_id: begin.challenge_id, credential: payload }),
1926	      });
1927	      const json = await res.json().catch(() => ({}));
1928	      if (!res.ok || !json.ok) throw new Error(json.detail || "Passkey xato");
1929	      els.loginScreen.hidden = true;
1930	      document.body.classList.remove("locked");
1931	      onAuthed();
1932	    } catch (e) {
1933	      if (e.name === "NotAllowedError" || e.name === "AbortError") return; // cancelled
1934	      showLoginError("Passkey bilan kirib bo'lmadi");
1935	    }
1936	  }
