1938	  let loggingIn = false;
1939	  async function onLoginSubmit(e) {
1940	    e.preventDefault();
1941	    if (loggingIn) return;
1942	    const username = els.loginUser.value.trim();
1943	    const password = els.loginPass.value;
1944	    if (!username) { showLoginError("Foydalanuvchi nomini kiriting"); return; }
1945	    if (!/^\d{4}$/.test(password)) { showLoginError("4 xonali PIN kiriting"); return; }
1946	    loggingIn = true;
1947	    els.loginError.hidden = true;
1948	    els.loginSubmit.disabled = true;
1949	    els.loginSubmit.textContent = "Kirilmoqda…";
1950	    try {
1951	      const res = await fetch("/api/auth/login", {
1952	        method: "POST",
1953	        headers: { "Content-Type": "application/json" },
1954	        body: JSON.stringify({ username, password }),
1955	      });
1956	      const json = await res.json().catch(() => ({}));
1957	      if (!res.ok || !json.ok) throw new Error(json.detail || "Kirish rad etildi");
1958	      els.loginScreen.hidden = true;
1959	      document.body.classList.remove("locked");
1960	      els.loginPass.value = "";
1961	      onAuthed();
1962	    } catch (err) {
1963	      showLoginError(err.message || "Xatolik");
1964	      els.loginPass.select();
1965	    } finally {
1966	      loggingIn = false;
1967	      els.loginSubmit.disabled = false;
1968	      els.loginSubmit.textContent = "Kirish";
1969	    }
1970	  }
