1972	  function togglePassword() {
1973	    const show = els.loginPass.type === "password";
1974	    els.loginPass.type = show ? "text" : "password";
1975	    els.passToggle.setAttribute("aria-label", show ? "Parolni yashirish" : "Parolni ko'rsatish");
1976	    els.passToggle.classList.toggle("is-on", show);
1977	  }
