1979	  if (els.loginForm) els.loginForm.addEventListener("submit", onLoginSubmit);
1980	  if (els.passToggle) els.passToggle.addEventListener("click", togglePassword);
1981	  // PIN: digits only, max 4.
1982	  if (els.loginPass) els.loginPass.addEventListener("input", (e) => {
1983	    const v = e.target.value.replace(/\D/g, "").slice(0, 4);
1984	    if (v !== e.target.value) e.target.value = v;
1985	  });
